\part Complete the frequency table.

You may use the tally column to help you.

\begin{center}
\begin{tabular}{|c|c|c|}
\hline
Time (minutes) & Tally & Frequency \\
\hline
$0 - 5$ & & \\
\hline
$6 - 10$ & & \\
\hline
$11 - 15$ & & \\
\hline
$16 - 20$ & & \\
\hline
$21 - 25$ & & \\
\hline
$26 - 30$ & & \\
\hline
\end{tabular}
\end{center}
\Marks{2}

\part Draw a bar chart to show this information.

Complete the scale on the frequency axis.
\Marks{3}

\part Use the bar chart to write down the modal group.

\AnswerLine[][]
\Marks{1}

\end{parts}

\begin{parts}
\part Find

\begin{subparts}
\subpart a multiple of 3 between 70 and 80,

\AnswerLine[][]
\Marks{1}

\subpart a factor of 63 between 5 and 10,

\AnswerLine[][]
\Marks{1}

\subpart a cube number between 60 and 90,

\AnswerLine[][]
\Marks{1}

\subpart the reciprocal of 7.

\AnswerLine[][]
\Marks{1}

