\begin{subparts}
\subpart Find the range.

\AnswerLine[][]
\Marks{1}

\subpart Calculate the mean.

\AnswerLine[][]
\Marks{3}

\subpart Find the probability that a customer picked at random buys more than 4 items.

\AnswerLine[][]
\Marks{2}

\end{subparts}

\part Carlotta buys a bicycle.

\begin{subparts}
\subpart The length, $l$\,cm, of the bicycle is 96\,cm, correct to the nearest centimetre.

Complete this statement about the value of $l$.

\AnswerLine[\makebox[1cm]{\hrulefill} $\leqslant l <$ \makebox[1cm]{\hrulefill}][]
\Marks{2}

\subpart The diameter of each bicycle wheel is 46\,cm.

Carlotta rides the bicycle a distance of 1.4\,km.

Calculate the number of complete revolutions that a wheel makes during this journey.

\AnswerLine[][]
\Marks{5}

\end{subparts}

\end{parts}

